window.HK_LC2 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["The woman is carrying a shovel.", "The woman is hiking in a field.", "The woman is filling a watering can.", "The woman is kneeling on the grass."], "optko": ["여자가 삽을 들고 있다.", "여자가 들판을 걷고 있다.", "여자가 물뿌리개를 채우고 있다.", "여자가 잔디에 무릎을 꿇고 있다."], "ans": 3, "audio": "Test02_01.mp3", "img": "hk_t2_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["Some people are walking along a road.", "One of the men is brushing off his shirt.", "Construction work is being done.", "A hose has been set on the ground."], "optko": ["몇몇 사람들이 길을 따라 걷고 있다.", "남자들 중 한 명이 그의 셔츠를 털고 있다.", "공사 작업이 진행되고 있다.", "호스가 땅에 놓여 있다."], "ans": 2, "audio": "Test02_02.mp3", "img": "hk_t2_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["A guitar is being played.", "A room is unoccupied.", "An instrument is being repaired.", "A box is propping a door open."], "optko": ["기타가 연주되고 있다.", "방에 사람이 없다.", "악기가 수리되고 있다.", "상자가 문을 받쳐 열어 놓고 있다."], "ans": 1, "audio": "Test02_03.mp3", "img": "hk_t2_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["The woman is hanging up a blanket.", "The woman is sorting some towels.", "The woman is making a bed.", "The woman is turning off a light."], "optko": ["여자가 담요를 걸고 있다.", "여자가 수건을 분류하고 있다.", "여자가 이불을 정돈하고 있다.", "여자가 불을 끄고 있다."], "ans": 2, "audio": "Test02_04.mp3", "img": "hk_t2_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Some items are on display.", "A woman is standing by a cash register.", "Produce is being handed to a shopper.", "Some people are pushing a shopping cart."], "optko": ["물품들이 진열되어 있다.", "한 여자가 계산대 옆에 서 있다.", "농산물이 쇼핑객에게 건네지고 있다.", "사람들이 쇼핑용 카트를 밀고 있다."], "ans": 0, "audio": "Test02_05.mp3", "img": "hk_t2_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Curtains separate the work areas.", "A monitor has been turned on.", "A remote control is lying on a chair.", "A desk is illuminated by a lamp."], "optko": ["커튼이 작업 구역들을 분리하고 있다.", "모니터가 켜져 있다.", "리모컨이 의자 위에 놓여 있다.", "책상이 전등으로 밝혀지고 있다."], "ans": 3, "audio": "Test02_06.mp3", "img": "hk_t2_q6.jpg"}, {"n": 7, "part": 2, "q": "Who owns this green sedan?", "qko": "누가 이 초록 세단을 소유하나요?", "opts": ["Can you drive there?", "In the owner's manual.", "It doesn't belong to me."], "optko": ["당신은 그곳으로 운전할 수 있나요?", "사용 설명서에요.", "제 것은 아니에요."], "ans": 2, "audio": "Test02_07.mp3"}, {"n": 8, "part": 2, "q": "Where is the nearest post office located?", "qko": "가장 가까운 우체국이 어디에 위치해 있나요?", "opts": ["It's a nearby store.", "About three blocks south.", "I bought some stamps."], "optko": ["인근의 가게예요.", "남쪽으로 세 블록 정도요.", "저는 우표 몇 개를 구입했어요."], "ans": 1, "audio": "Test02_08.mp3"}, {"n": 9, "part": 2, "q": "Why wasn't the recycling taken out?", "qko": "왜 재활용품이 밖에 내놓아지지 않았나요?", "opts": ["The garbage can.", "Scott forgot to do it.", "Oh, a collection agency."], "optko": ["쓰레기통이요.", "Scott이 그걸 하는 것을 잊었어요.", "아, 수거 대행 회사요."], "ans": 1, "audio": "Test02_09.mp3"}, {"n": 10, "part": 2, "q": "How much is this office's rental fee?", "qko": "이 사무실의 대여 비용은 얼마인가요?", "opts": ["$3,000 monthly.", "For government officials only.", "Both items were free."], "optko": ["한 달에 3천 달러입니다.", "공무원들만을 위한 거예요.", "두 물품 모두 무료였어요."], "ans": 0, "audio": "Test02_10.mp3"}, {"n": 11, "part": 2, "q": "Would you mind opening the window?", "qko": "창문을 열어도 괜찮으신가요?", "opts": ["The account has been closed.", "Isn't it too cold outside?", "No, not until last spring."], "optko": ["그 계좌는 해지되었어요.", "밖이 너무 춥지 않나요?", "아니요, 지난봄이나 되어서요."], "ans": 1, "audio": "Test02_11.mp3"}, {"n": 12, "part": 2, "q": "The projector in the conference room isn't working.", "qko": "회의실의 프로젝터가 작동하지 않아요.", "opts": ["If there's enough room.", "Yes, a presentation.", "Holly also reported that problem."], "optko": ["만약 충분한 공간이 있다면요.", "네, 발표요.", "Holly도 그 문제를 보고했어요."], "ans": 2, "audio": "Test02_12.mp3"}, {"n": 13, "part": 2, "q": "When will we update the dessert options on our menu?", "qko": "언제 우리 메뉴의 디저트 선택권을 업데이트 할까요?", "opts": ["Two types of cake were just added.", "The screening is next Friday.", "Those are very good suggestions."], "optko": ["두 종류의 케이크가 막 추가되었어요.", "상영은 다음 주 금요일이에요.", "그것들은 매우 좋은 제안들이에요."], "ans": 0, "audio": "Test02_13.mp3"}, {"n": 14, "part": 2, "q": "How are you going to finish your speech by the deadline?", "qko": "당신의 연설을 어떻게 마감일까지 끝낼 건가요?", "opts": ["A list of speakers.", "I completely agree.", "I'm concerned about that too."], "optko": ["연설자들 목록이요.", "저는 전적으로 동의해요.", "저도 그게 걱정돼요."], "ans": 2, "audio": "Test02_14.mp3"}, {"n": 15, "part": 2, "q": "You're scheduled for the night shift, correct?", "qko": "당신은 야간 근무 일정이 잡혀 있죠, 맞나요?", "opts": ["The goods shifted during transit.", "Last night's videoconference.", "Not this evening."], "optko": ["그 상품은 운송 중에 움직였어요.", "지난밤의 영상 회의요.", "오늘 저녁은 아니에요."], "ans": 2, "audio": "Test02_15.mp3"}, {"n": 16, "part": 2, "q": "Were enough gift bags purchased for banquet attendees?", "qko": "연회 참석자들을 위한 선물 가방이 충분히 구입되었나요?", "opts": ["I think you'll like your present.", "We were a few short.", "Programs for the event."], "optko": ["저는 당신이 선물을 좋아할 거라고 생각해요.", "조금 모자랐어요.", "행사를 위한 프로그램들이요."], "ans": 1, "audio": "Test02_16.mp3"}, {"n": 17, "part": 2, "q": "Would you be interested in a beverage?", "qko": "음료를 드실 생각이 있으신가요?", "opts": ["Thanks, but I'll pass.", "No, neither of the plates.", "What an interesting outfit!"], "optko": ["감사하지만, 사양할게요.", "아니요, 두 요리들 모두 아니에요.", "정말 흥미로운 의상이네요!"], "ans": 0, "audio": "Test02_17.mp3"}, {"n": 18, "part": 2, "q": "Will it be a while until the train arrives?", "qko": "기차가 도착할 때까지 좀 걸릴까요?", "opts": ["I haven't heard anything.", "I registered for a training session.", "Directly from Berlin."], "optko": ["저는 아무것도 듣지 못했어요.", "저는 교육 과정에 등록했어요.", "베를린으로부터 곧장이요."], "ans": 0, "audio": "Test02_18.mp3"}, {"n": 19, "part": 2, "q": "Can you please listen to your music with earphones?", "qko": "이어폰으로 음악을 들어주시겠어요?", "opts": ["I can't use my phone.", "Yes. Sorry to disturb you.", "Where's the musical being held?"], "optko": ["저는 제 휴대 전화를 사용할 수 없어요.", "네. 당신을 방해해서 죄송해요.", "뮤지컬은 어디에서 열리나요?"], "ans": 1, "audio": "Test02_19.mp3"}, {"n": 20, "part": 2, "q": "What's your firm's biggest challenge this year?", "qko": "올해 당신 회사의 가장 큰 도전은 무엇인가요?", "opts": ["A highly competitive market.", "It was a challenging hike.", "It's bigger than I thought."], "optko": ["매우 경쟁적인 시장이요.", "힘든 도보 여행이었어요.", "제가 생각했던 것보다 더 크네요."], "ans": 0, "audio": "Test02_20.mp3"}, {"n": 21, "part": 2, "q": "Where should these wooden boards be stacked?", "qko": "이 나무로 된 판자들은 어디에 쌓아져야 하나요?", "opts": ["Beside the garage.", "It's high-quality wood.", "You should consider going as well."], "optko": ["차고 옆에요.", "이건 품질이 좋은 나무예요.", "당신도 가는 것을 고려해야 해요."], "ans": 0, "audio": "Test02_21.mp3"}, {"n": 22, "part": 2, "q": "Who rearranged the layout of the lobby?", "qko": "누가 로비의 배치를 바꾸었나요?", "opts": ["Sure, I can arrange a taxi for you.", "Please lay the shirts on the shelves.", "The office manager."], "optko": ["물론이죠, 저는 당신을 위해 택시를 마련할 수 있어요.", "선반 위에 셔츠를 놓아 주세요.", "사무실 관리자요."], "ans": 2, "audio": "Test02_22.mp3"}, {"n": 23, "part": 2, "q": "When will workers receive their annual bonuses?", "qko": "직원들이 언제 연례 보너스를 받을까요?", "opts": ["With their next paychecks.", "Yes, a generous amount.", "I have the receipt in my bag."], "optko": ["다음 급여와 함께요.", "네, 넉넉한 액수예요.", "저는 가방에 영수증을 갖고 있어요."], "ans": 0, "audio": "Test02_23.mp3"}, {"n": 24, "part": 2, "q": "The battery in this wristwatch needs to be replaced.", "qko": "이 손목시계의 배터리가 교체되어야 해요.", "opts": ["I watched that movie yesterday.", "Oh, I didn't realize it was dead.", "Thanks for coming to my place."], "optko": ["저는 그 영화를 어제 봤어요.", "아, 이게 다 닳았는지 깨닫지 못했어요.", "저의 집에 와주셔서 감사합니다."], "ans": 1, "audio": "Test02_24.mp3"}, {"n": 25, "part": 2, "q": "A shipment of notepads arrived at the school this morning.", "qko": "오늘 아침 학교에 메모지 배송품이 도착했어요.", "opts": ["I'd recommend taking a cruise ship.", "But I just ordered pens and pencils.", "Middleton High School."], "optko": ["저는 유람선을 타는 것을 추천해요.", "하지만 저는 펜과 연필만 주문했어요.", "Middleton 고등학교요."], "ans": 1, "audio": "Test02_25.mp3"}, {"n": 26, "part": 2, "q": "Does Ms. Wallace have time to meet us this afternoon?", "qko": "Ms. Wallace가 오늘 오후에 우리를 만날 시간이 있나요?", "opts": ["I appreciate you getting together with me on short notice.", "I'll check her schedule.", "She reviewed the project timeline."], "optko": ["갑작스러운 통지에도 저와 만나주셔서 감사합니다.", "제가 그녀의 일정을 확인할게요.", "그녀는 프로젝트 일정을 검토했어요."], "ans": 1, "audio": "Test02_26.mp3"}, {"n": 27, "part": 2, "q": "Why are the display cases near our store's entrance empty?", "qko": "우리 가게의 입구 근처에 있는 진열대가 왜 비어 있나요?", "opts": ["To make room for new inventory.", "Next to the exit.", "Please empty them out."], "optko": ["새 재고를 놓을 공간을 만들기 위해서요.", "출구 옆이요.", "그것들을 비워 주세요."], "ans": 0, "audio": "Test02_27.mp3"}, {"n": 28, "part": 2, "q": "Don't these hats have to be returned to the manufacturer?", "qko": "이 모자들이 제조사로 반납되어야 하지 않나요?", "opts": ["A popular line of winter apparel.", "A factory supervisor.", "Yes, they have defects."], "optko": ["겨울 의류 중 인기 있는 종류예요.", "공장 관리자요.", "네, 그것들은 결함이 있어요."], "ans": 2, "audio": "Test02_28.mp3"}, {"n": 29, "part": 2, "q": "Are any of the seats on the flight to Rome still available?", "qko": "로마행 비행편에 아직 이용할 수 있는 좌석이 있나요?", "opts": ["I've traveled to Rome twice.", "No, they are fully booked.", "I can help you find your seat in the theater."], "optko": ["저는 로마를 두 번 여행해 봤어요.", "아니요, 그것들은 모두 예약됐어요.", "제가 당신이 극장에서 자리를 찾는 것을 도와드릴 수 있어요."], "ans": 1, "audio": "Test02_29.mp3"}, {"n": 30, "part": 2, "q": "What did you want to talk to me about earlier today?", "qko": "당신은 오늘 일찍 제게 무엇에 대해 말하고 싶어 했나요?", "opts": ["That's correct. Today and tomorrow.", "As early as possible.", "My transfer to our overseas office."], "optko": ["맞아요. 오늘과 내일이요.", "가능한 한 빨리요.", "우리 해외 지사로 제가 전근 가는 것이요."], "ans": 2, "audio": "Test02_30.mp3"}, {"n": 31, "part": 2, "q": "The winner of the fiction prize will be announced sometime this week.", "qko": "소설 부문의 수상자가 이번 주 중으로 발표될 거예요.", "opts": ["How will we be notified?", "I was surprised that he won.", "This year's fiction book fair was a huge success."], "optko": ["우리가 어떻게 통지를 받을까요?", "저는 그가 상을 받은 것에 놀랐어요.", "올해의 소설책 박람회는 대성공이었어요."], "ans": 0, "audio": "Test02_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Ca", "audio": "Test02_32-34.mp3", "qs": [{"n": 32, "q": "What problem does the man mention?", "opts": ["A package was sent to the wrong place.", "A letter contains inaccurate details.", "A courier arrived at a destination late.", "An order is going to be changed."], "ans": 0, "ko": "남자는 무슨 문제를 언급하는가?"}, {"n": 33, "q": "What does the woman inquire about?", "opts": ["Whether the man wants a quote", "When the man received an item", "Whether the man recognized some information", "Where the man currently works"], "ans": 2, "ko": "여자는 무엇에 관해 문의하는가?"}, {"n": 34, "q": "What does the woman say she will do?", "opts": ["Send out a worker", "Waive a fee", "Look up an address", "Inform a sender"], "ans": 0, "ko": "여자는 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "Thank you for calling Index Shipping. My name is Valerie. How can I help you?", "ko": "Index 운송 회사에 전화해주셔서 감사합니다. 제 이름은 Valerie입니다. 무엇을 도와드릴까요?"}, {"sp": "M", "en": "I want to report a mistaken delivery. When I came home from work today, I noticed a large box outside my door. It has my address on it but someone else's name.", "ko": "저는 잘못된 배송에 대해 알려드리고 싶습니다. 제가 오늘 퇴근하고 집에 왔을 때, 문 밖에서 큰 상자를 발견했어요. 그것에는 제 주소가 있었지만 다른 누군가의 이름이 있었어요."}, {"sp": "W", "en": "Oh, I see. And you weren't expecting a package? Did you recognize the sender's information?", "ko": "아, 알겠습니다. 그럼 소포를 기다리고 계셨던 건 아니죠? 발송인의 정보를 알아보셨나요?"}, {"sp": "M", "en": "No, neither.", "ko": "아니요, 둘 다 아니에요."}, {"sp": "W", "en": "Hmm . . . The sender probably wrote the wrong address on the parcel. I'll have a courier stop by your place and pick it up tomorrow morning.", "ko": "흠... 발송인이 아마 소포에 잘못된 주소를 적은 것 같네요. 배달원이 내일 아침에 당신의 집에 들러서 그것을 가져가게 하겠습니다."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "W / M1 / M2", "audio": "Test02_35-37.mp3", "qs": [{"n": 35, "q": "Where is the conversation most likely taking place?", "opts": ["In a hotel", "In a staffing agency", "In a pharmacy", "In a research center"], "ans": 3, "ko": "대화는 어디에서 일어나고 있는 것 같은가? (A) 호텔에서 (B) 채용 업체에서 (C) 약국에서 (D) 연구 센터에서"}, {"n": 36, "q": "What task will Steve carry out?", "opts": ["Leading an orientation session", "Giving a facility tour", "Assembling a research team", "Retrieving medicine samples"], "ans": 1, "ko": "Steve가 수행할 업무는 무엇인가? (A) 오리엔테이션을 이끄는 것 (B) 시설 견학을 시켜주는 것 (C) 연구팀을 소집하는 것 (D) 약 샘플을 회수하는 것"}, {"n": 37, "q": "What do the men agree to do?", "opts": ["Share some study results", "Meet in the afternoon", "Introduce new employees", "Work overtime hours"], "ans": 1, "ko": "남자들은 무엇을 하는 것에 동의하는가? (A) 연구 결과를 공유한다. (B) 오후에 만난다. (C) 새로운 직원들을 소개한다. (D) 야근을 한다."}], "script": [{"sp": "W", "en": "Steve, this is our newly hired laboratory technician, Edward Germaine. Edward, this is Steve Meyers, our senior researcher.", "ko": "Steve, 이 분은 새로 고용된 실험실 기술자인 Edward Germaine이에요. Edward, 이 분은 우리 수석 연구원인 Steve Meyers예요."}, {"sp": "M1", "en": "Welcome to Milton Research Firm. Will you be working on the upcoming allergy medicine study?", "ko": "Milton 연구 회사에 오신 것을 환영해요. 곧 있을 알레르기 연구를 진행하실 건가요?"}, {"sp": "M2", "en": "I don't know yet. My orientation is today, so I haven't been assigned to a project yet.", "ko": "아직 모르겠어요. 제 오리엔테이션이 오늘이라서 아직 프로젝트에 배정되지 않았어요."}, {"sp": "W", "en": "Ms. Adams will tell him which team he'll be on tomorrow. By the way, Steve, would you be able to show Edward around the laboratory at some point today?", "ko": "Ms. Adams가 내일 그에게 어떤 팀이 될지 알려줄 거예요. 그건 그렇고, Steve, 오늘 중에 Edward에게 실험실을 안내해주실 수 있나요?"}, {"sp": "M1", "en": "Of course. When is a good time for you, Edward?", "ko": "물론이죠. 언제가 좋으세요, Edward?"}, {"sp": "M2", "en": "I should be free at 1 P.M. Is that OK?", "ko": "저는 오후 1시에 한가할 거예요. 괜찮으신가요?"}, {"sp": "M1", "en": "Certainly. Let's meet in the break room.", "ko": "그럼요. 휴게실에서 만나도록 하죠."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "M / W", "audio": "Test02_38-40.mp3", "qs": [{"n": 38, "q": "Why is the man calling?", "opts": ["To request an extension", "To confirm a facility's hours", "To check an item's availability", "To cancel an appointment"], "ans": 2, "ko": "남자는 왜 전화를 하고 있는가? (A) 연장을 요청하기 위해 (B) 시설 운영 시간을 확인하기 위해 (C) 제품의 이용 가능성을 확인하기 위해 (D) 약속을 취소하기 위해"}, {"n": 39, "q": "Why does the woman say, \"that publication is part of our rare book collection\"?", "opts": ["To explain a decision", "To address a complaint", "To give a compliment", "To indicate a problem"], "ans": 3, "ko": "여자는 왜 \"그 출판물은 저희 희귀본 소장품의 일부입니다\"라고 말하는가? (A) 결정을 설명하기 위해 (B) 불만을 처리하기 위해 (C) 칭찬을 하기 위해 (D) 문제를 나타내기 위해"}, {"n": 40, "q": "What will the woman probably do next?", "opts": ["Locate some reading material", "Verify a book title", "Change a reservation", "Transfer a call"], "ans": 3, "ko": "여자는 다음에 무엇을 할 것 같은가? (A) 몇몇 읽을거리를 찾아낸다. (B) 책 제목을 확인한다. (C) 예약을 변경한다. (D) 전화를 다른 사람 번호로 돌려준다."}], "script": [{"sp": "M", "en": "Hi. I'm calling to see if your library has the book Distant Stars available to check out.", "ko": "안녕하세요. 저는 도서관에 대출 가능한 Distant Stars라는 책이 있는지 확인하기 위해 전화드립니다."}, {"sp": "W", "en": "Just a minute . . . Yes, we have it, sir. But, well . . . that publication is part of our rare book collection. Books in that section cannot be taken out of our facility.", "ko": "잠시만요… 네, 있습니다, 손님. 하지만, 음… 그 출판물은 저희 희귀본 소장품의 일부입니다. 그 구역에 있는 책들은 저희 시설 밖으로 반출될 수 없습니다."}, {"sp": "M", "en": "I see. In that case, I guess I'll have to look over the book there. Would it be possible to reserve a private reading room from 4 P.M. to 7 P.M. today?", "ko": "알겠습니다. 그런 경우라면, 거기서 책을 살펴봐야 하겠네요. 오늘 오후 4시부터 7시까지 개인 열람실을 예약할 수 있을까요?"}, {"sp": "W", "en": "For that, I'll have to transfer you to our facilities department. Please stay on the line while I connect you.", "ko": "그 점에 대해서는, 저희 시설 부서로 전화를 돌려드려야 할 것 같습니다. 제가 연결해드릴 동안 전화를 끊지 말고 기다려주세요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "W / M", "audio": "Test02_41-43.mp3", "qs": [{"n": 41, "q": "Who most likely is the man?", "opts": ["An interior decorator", "A divisional manager", "A language instructor", "A real estate agent"], "ans": 2, "ko": "남자는 누구인 것 같은가? (A) 실내 장식가 (B) 부서 관리자 (C) 언어 강사 (D) 부동산 중개인"}, {"n": 42, "q": "What does the woman mention about the new office space?", "opts": ["It is currently vacant.", "It is located nearby.", "It has multiple conference rooms.", "It was recently renovated."], "ans": 0, "ko": "여자는 새로운 사무실 공간에 관해 무엇을 언급하는가? (A) 현재 비어 있다. (B) 가까운 곳에 위치해 있다. (C) 다수의 회의실을 가지고 있다. (D) 최근에 개조되었다."}, {"n": 43, "q": "What does the man ask the woman to do?", "opts": ["Provide contact information", "Check some blueprints", "Reschedule a conference call", "Send a text message"], "ans": 3, "ko": "남자는 여자에게 무엇을 해달라고 요청하는가? (A) 연락처를 제공한다. (B) 청사진을 확인한다. (C) 전화 회의의 일정을 변경한다. (D) 문자 메시지를 보낸다."}], "script": [{"sp": "W", "en": "Thanks for stopping by our office again this week, Mr. Long. Your Chinese lessons are really helping the staff.", "ko": "이번 주에 저희 사무실에 다시 들러 주셔서 감사합니다, Mr. Long. 당신의 중국어 수업이 직원들에게 정말 도움이 되고 있어요."}, {"sp": "M", "en": "Certainly. I'll see you here at the same time next Wednesday!", "ko": "그럼요. 다음 주 수요일 같은 시간에 여기서 뵐게요!"}, {"sp": "W", "en": "OK. Oh, that reminds me . . . We'll be relocating our offices shortly. Our new space is empty now, but we are planning to redecorate it before we move in, and I'm not sure how long that will take. So, you might have to go to our new address.", "ko": "좋아요. 아, 그러고 보니 생각나네요… 저희는 곧 사무실을 이전할 거예요. 저희의 새로운 장소는 지금 비어 있지만, 저희가 이사하기 전에 그곳을 새로 장식하려고 계획하고 있고, 그게 얼마나 걸릴지 잘 모르겠어요. 그래서 저희의 새로운 주소로 가셔야 할 수도 있어요."}, {"sp": "M", "en": "I understand. Could you text me when you find out the exact details?", "ko": "알겠습니다. 정확한 세부 사항을 알게 되시면 저에게 문자를 보내주시겠어요?"}, {"sp": "W", "en": "Of course. I have a videoconference with the head decorator tomorrow morning. I should have more information for you then.", "ko": "물론이죠. 내일 아침에 수석 실내 장식가와의 영상 회의가 있어요. 그때 당신을 위한 정보가 더 있을 거예요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "W1 / M / W2", "audio": "Test02_44-46.mp3", "qs": [{"n": 44, "q": "What will most likely take place on Friday?", "opts": ["A corporate fund-raiser", "An award banquet", "A birthday party", "A farewell gathering"], "ans": 3, "ko": "금요일에 무슨 일이 일어날 것 같은가? (A) 기업 모금 행사 (B) 시상식 연회 (C) 생일 파티 (D) 송별회 모임"}, {"n": 45, "q": "What does the man imply when he says, \"She said she has to meet with an important client\"?", "opts": ["He is concerned about a colleague.", "He wants to change an itinerary.", "He is surprised by some news.", "He needs to confirm some arrangements."], "ans": 2, "ko": "남자는 \"그녀는 중요한 고객과 만나야 한다고 말했어요\"라고 말할 때 무엇을 의도하는가? (A) 그는 동료에 대해 걱정한다. (B) 그는 여행 일정을 변경하고 싶어 한다. (C) 그는 어떤 소식에 놀랐다. (D) 그는 몇 가지 계획을 확인해야 한다."}, {"n": 46, "q": "What is mentioned about the catering service?", "opts": ["It is too expensive.", "It was used for another event.", "It has good online reviews.", "It was booked yesterday."], "ans": 1, "ko": "출장 연회 업체에 관해 무엇이 언급되는가? (A) 너무 비싸다. (B) 다른 행사에 이용되었다. (C) 좋은 온라인 후기들이 있다. (D) 어제 예약되었다."}], "script": [{"sp": "W1", "en": "Everyone, Ms. Clemons changed the dates for her business trip, so she can join Meredith's retirement party this Friday after all.", "ko": "여러분, Ms. Clemons가 그녀의 출장 날짜를 변경해서, 결국 이번 주 금요일 Meredith의 은퇴 파티에 함께할 수 있어요."}, {"sp": "M", "en": "Really? She said she has to meet with an important client. I guess plans changed. Meredith will be happy that she can come.", "ko": "정말이요? 그녀는 중요한 고객과 만나야 한다고 말했었어요. 계획이 바뀐 것 같네요. Meredith는 그녀가 올 수 있는 것에 기뻐할 거예요."}, {"sp": "W1", "en": "Definitely. By the way, Jake, did you purchase decorations to put up in the conference room?", "ko": "물론이죠. 그건 그렇고, Jake, 회의실에 놓을 장식품을 구입했나요?"}, {"sp": "M", "en": "Yes. They were more expensive than I thought, though. I spent more than the budgeted amount, unfortunately.", "ko": "네. 하지만, 제가 생각했던 것보다 더 비쌌어요. 유감스럽게도, 예산 금액보다 더 많이 사용했어요."}, {"sp": "W2", "en": "Don't worry. I got an e-mail from the catering service yesterday saying we'll be charged a discounted rate . . . um . . . since we hired them for last year's holiday office party.", "ko": "걱정하지 마세요. 저는 어제 출장 연회 업체로부터 우리가 할인된 요금을 청구받게 될 거라는 이메일을 받았어요… 음… 우리가 작년 연휴 회사 파티에 그들을 고용했기 때문이에요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "M / W", "audio": "Test02_47-49.mp3", "qs": [{"n": 47, "q": "What does the woman want to do?", "opts": ["Find additional roommates", "Rent a house", "Sell some property", "View some real estate"], "ans": 2, "ko": "여자는 무엇을 하고 싶어 하는가? (A) 추가 룸메이트를 찾는다. (B) 집을 임대한다. (C) 건물을 판다. (D) 부동산을 보러 다닌다."}, {"n": 48, "q": "What happened this morning?", "opts": ["An offer was rejected.", "An appointment was made.", "An agent was hired.", "A document was printed."], "ans": 1, "ko": "오늘 아침에 무슨 일이 일어났는가? (A) 제안이 거절되었다. (B) 약속이 잡혔다. (C) 중개인이 고용되었다. (D) 서류가 인쇄되었다."}, {"n": 49, "q": "What did the agent provide information about?", "opts": ["Insurance rates", "Local businesses", "Monthly fees", "Employment opportunities"], "ans": 1, "ko": "중개인은 무엇에 관한 정보를 제공했는가? (A) 보험료 (B) 근거리의 업체들 (C) 월간 이용료 (D) 채용 기회들"}], "script": [{"sp": "M", "en": "Young-mi, is anyone interested in the house you're trying to sell?", "ko": "Young-mi, 당신이 팔려고 하는 집에 관심 있어 하는 사람이 있나요?"}, {"sp": "W", "en": "Actually, the real estate agent I hired called me about that an hour ago. He said that there's a woman who's interested. She contacted him this morning to set up a time to view my home. I guess she saw some pictures of it and was very impressed.", "ko": "사실, 제가 고용한 부동산 중개인이 한 시간 전에 그것에 대해 제게 전화했어요. 그는 관심 있어 하는 여자가 있다고 말했어요. 그녀는 오늘 아침에 제 집을 둘러볼 시간을 정하기 위해 그에게 연락했어요. 제 생각엔 그녀가 집의 사진을 몇 장 보고 매우 감명을 받은 것 같아요."}, {"sp": "M", "en": "Well, I hope she decides to put an offer on the place.", "ko": "음, 나는 그녀가 그 집에 대한 가격을 제시하기로 결정하기를 바라요."}, {"sp": "W", "en": "I'm feeling optimistic. Apparently, the potential buyer was very happy when my agent told her that there is a grocery store and a fitness center nearby.", "ko": "저는 낙관적이에요. 듣자 하니, 제 중개인이 근처에 식료품점과 헬스장이 있다고 잠재적 구매자에게 말했을 때, 그녀가 매우 기뻐했대요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "W / M", "audio": "Test02_50-52.mp3", "qs": [{"n": 50, "q": "Where is the conversation taking place?", "opts": ["At a tailoring shop", "At a dry-cleaning business", "At a postal office", "At a clothing store"], "ans": 1, "ko": "대화는 어디에서 일어나고 있는가? (A) 양복점 (B) 드라이클리닝 업체 (C) 우체국 (D) 옷 가게"}, {"n": 51, "q": "What problem does the man identify?", "opts": ["An item has been damaged.", "Some personnel took a sick day.", "Some equipment is malfunctioning.", "A bill is incorrect."], "ans": 2, "ko": "남자는 어떤 문제를 밝히는가? (A) 상품이 손상되었다. (B) 몇몇 직원들이 병가를 냈다. (C) 장비가 제대로 작동하지 않는다. (D) 청구서가 부정확하다."}, {"n": 52, "q": "What will the woman probably do next?", "opts": ["Request a refund", "Provide an address", "Examine a receipt", "Make a payment"], "ans": 1, "ko": "여자는 다음에 무엇을 할 것 같은가? (A) 환불을 요청한다. (B) 주소를 제공한다. (C) 영수증을 검토한다. (D) 대금을 지불한다."}], "script": [{"sp": "W", "en": "Good morning. I'm here to pick up my clothes that I dropped off yesterday. I requested the express cleaning service.", "ko": "안녕하세요. 어제 맡긴 제 옷을 가지러 왔어요. 저는 신속 세탁 서비스를 요청했어요."}, {"sp": "M", "en": "I'm very sorry, ma'am, but your items are not quite ready yet. One of our machines unexpectedly broke down last night. It is currently being fixed.", "ko": "정말 죄송합니다, 손님. 하지만 손님의 물품이 아직 준비되지 않았습니다. 저희 기계들 중 하나가 어젯밤에 갑자기 고장 났거든요. 그것은 지금 수리되고 있습니다."}, {"sp": "W", "en": "I really needed everything this morning. That's why I chose to pay a premium.", "ko": "저는 오늘 아침에 모든 게 정말 필요했어요. 그게 제가 추가 금을 내기로 했던 이유예요."}, {"sp": "M", "en": "I understand. We will refund you the extra amount, of course. And if you give us your address, we'll deliver the clothes to your residence at no extra charge this evening.", "ko": "알겠습니다. 물론 저희가 추가 금액을 환불해드리겠습니다. 그리고 손님의 주소를 알려 주시면, 저희가 오늘 저녁에 추가 요금 없이 옷을 댁으로 배달해드리겠습니다."}, {"sp": "W", "en": "OK. Do you have a pen I can use?", "ko": "좋아요. 제가 쓸 수 있는 펜이 있나요?"}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn", "audio": "Test02_53-55.mp3", "qs": [{"n": 53, "q": "Why does the woman need assistance?", "opts": ["A phone isn't turning on.", "A product manual is missing.", "A screen is broken.", "A button is stuck."], "ans": 2, "ko": "여자는 왜 도움이 필요한가?"}, {"n": 54, "q": "What does the man ask about?", "opts": ["Which product was selected", "When a purchase was made", "How a fee was paid", "Why an item was returned"], "ans": 1, "ko": "남자는 무엇에 관해 문의하는가?"}, {"n": 55, "q": "According to the man, what will the woman receive?", "opts": ["A full refund", "A free accessory", "A software upgrade", "A new device"], "ans": 3, "ko": "남자에 따르면, 여자는 무엇을 받을 것인가?"}], "script": [{"sp": "W", "en": "Hi. I'm wondering if you can assist me. There's an issue with the smartphone I bought here recently. It turns on fine, but I noticed a small crack on the display.", "ko": "안녕하세요. 저를 도와주실 수 있는지 궁금해요. 제가 최근에 여기서 산 스마트폰에 문제가 있어서요. 잘 켜지긴 하는데, 화면에 있는 작은 금을 발견했어요."}, {"sp": "M", "en": "Yes, I see what you mean. When did you buy the device?", "ko": "네, 무슨 말씀이신지 알겠습니다. 언제 기기를 구입하셨나요?"}, {"sp": "W", "en": "Just last Tuesday, when a special discount on the product was being offered.", "ko": "바로 지난 화요일에요, 이 제품에 대해 특별 할인이 제공되고 있을 때요."}, {"sp": "M", "en": "Well, you're still within our 90-day store warranty period.", "ko": "음, 아직 90일짜리 상점 품질 보증 기간 중이시네요."}, {"sp": "W", "en": "So, does that mean the display can be fixed for free?", "ko": "그럼 화면을 무료로 수리할 수 있다는 말씀이신가요?"}, {"sp": "M", "en": "Even better. We'll give you another unit at no cost.", "ko": "훨씬 더 좋은 거죠. 저희가 다른 상품 한 개를 무료로 드리겠습니다."}, {"sp": "W", "en": "Oh, wonderful! Thank you.", "ko": "아, 정말 좋네요! 감사합니다."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test02_56-58.mp3", "qs": [{"n": 56, "q": "Where most likely is the conversation taking place?", "opts": ["At a ticket counter", "In a storage facility", "In an elevator", "At a security desk"], "ans": 3, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 57, "q": "What does the man say about his driver's license?", "opts": ["It is a temporary replacement.", "It was left at home.", "It is going to expire soon.", "It was issued last year."], "ans": 1, "ko": "남자는 그의 운전면허증에 관해 무엇을 말하는가?"}, {"n": 58, "q": "What will the man probably do next?", "opts": ["Exchange a purchase", "Reschedule an appointment", "Show an access pass", "Fill out a document"], "ans": 3, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Excuse me. I have an appointment with Gina Patel on the 18th floor. How can I access the elevators?", "ko": "실례합니다. 저는 18층에서 Gina Patel과 약속이 있어요. 엘리베이터를 어떻게 이용할 수 있나요?"}, {"sp": "W", "en": "First, visitors must check in here. If you show me a piece of identification, I'll provide an electronic pass. Your ID will be kept here until you return.", "ko": "우선, 방문객들은 여기에서 등록하셔야 합니다. 저에게 신분증을 보여주시면, 제가 전자 출입증을 드리겠습니다. 신분증은 돌아오실 때까지 여기에 보관될 겁니다."}, {"sp": "M", "en": "Will my passport be suitable? I left my driver's license at my apartment.", "ko": "제 여권이 적합할까요? 제가 운전면허증을 제 아파트에 두고 왔거든요."}, {"sp": "W", "en": "That's fine. And now you just need to complete this form. It asks you for some personal details—your phone number, the purpose of your visit, and so on.", "ko": "괜찮습니다. 그리고 이제 이 양식만 작성해주시면 됩니다. 그것은 당신의 전화 번호, 방문 목적 등 몇 가지 개인 세부 사항들을 묻습니다."}, {"sp": "M", "en": "OK . . . I'll do that now.", "ko": "네… 지금 할게요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn", "audio": "Test02_59-61.mp3", "qs": [{"n": 59, "q": "Where do the speakers most likely work?", "opts": ["At a department store", "At a marketing firm", "At a cosmetics company", "At a technology firm"], "ans": 1, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 60, "q": "What problem does the man mention?", "opts": ["An online system was slow.", "A flight will be delayed.", "An offer has been refused.", "A document is outdated."], "ans": 0, "ko": "남자는 어떤 문제를 언급하는가?"}, {"n": 61, "q": "According to the man, what did Janice Miller do?", "opts": ["Requested a status report", "Uploaded some files", "Altered some designs", "E-mailed a department head"], "ans": 1, "ko": "남자에 따르면, Janice Miller는 무엇을 했는가?"}], "script": [{"sp": "W", "en": "How does everyone on your team feel about the newly implemented filing system, Trent?", "ko": "당신의 팀에서는 모두들 새로 시행된 서류 정리 시스템에 대해 어떻게 생각하나요, Trent?"}, {"sp": "M", "en": "Well, they definitely like that sharing files online is much easier now. That's really helpful when we're considering designs to use for advertising campaigns. However, it was running a bit slow yesterday, so that caused some delays.", "ko": "음, 그들은 확실히 온라인에서 파일을 공유하는 것이 이제 훨씬 쉽다고 좋아해요. 그것은 저희가 광고 캠페인에 사용할 디자인을 검토할 때 정말 도움이 돼요. 하지만, 어제 좀 느리게 작동해서, 일부 지연을 야기했어요."}, {"sp": "W", "en": "OK. I'll call the IT department and ask them to check on that. By the way, Mr. Nolan just asked me about the status of the Glowfresh Cosmetics commercial.", "ko": "알겠어요. 제가 IT 부서에 전화해서 그것에 대해 확인해달라고 그들에게 요청할게요. 그건 그렇고, Mr. Nolan이 방금 저에게 Glowfresh 화장품 회사의 광고 진행 상황에 대해 물어봤어요."}, {"sp": "M", "en": "Janice Miller just uploaded some storyboard files to the system. If you log in and click on Designs, you can see what she has done so far.", "ko": "Janice Miller가 방금 시스템에 몇몇 스토리 보드 파일들을 업로드했어요. 로그인해서 Designs를 클릭하면, 그녀가 지금까지 한 것을 보실 수 있어요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "M-Cn / W-Br", "audio": "Test02_62-64.mp3", "qs": [{"n": 62, "q": "Who most likely is the woman?", "opts": ["A marketing researcher", "A restaurant manager", "A travel agent", "A financial advisor"], "ans": 3, "ko": "여자는 누구인 것 같은가?"}, {"n": 63, "q": "Look at the graphic. Where will the speakers dine?", "opts": ["At BBQ Heaven", "At John's Kitchen", "At Fire BBQ", "At Red Tavern"], "ans": 3, "ko": "시각 자료를 보시오. 화자들은 어디에서 식사할 것인가?"}, {"n": 64, "q": "What will the man probably do next?", "opts": ["Retrieve a coat", "Check a menu", "Make a reservation", "Notify a secretary"], "ans": 0, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Thank you for meeting with me, Ms. Reynolds. I plan to adopt much of your investment advice, and I look forward to working with you more in the future. And now I'd like to take you to lunch, if that's all right.", "ko": "저와 만나주셔서 감사합니다, Ms. Reynolds. 저는 당신의 투자 조언 대부분을 채택할 계획이고, 미래에 당신과 같이 더 일하게 되기를 기대합니다. 그리고 괜찮으시다면 이제 당신께 점심을 대접하고 싶어요."}, {"sp": "W", "en": "Certainly. I've heard the Fire BBQ has great Southern food. We could go there.", "ko": "물론이죠. 저는 Fire BBQ에서 훌륭한 남부 음식을 판매한다고 들었어요. 저희가 거기에 가면 될 것 같아요."}, {"sp": "M", "en": "While I really enjoy that restaurant, it's closed for renovations. But there's another great option just a bit further down the road from that place. It has the best ribs in town.", "ko": "저는 그 식당을 매우 좋아하지만, 그곳은 보수로 인해 문을 닫았어요. 하지만, 그 장소에서 길을 좀 더 내려가면 다른 아주 좋은 선택권이 있어요. 이 지역에서 갈비가 가장 맛있는 곳이에요."}, {"sp": "W", "en": "All right. Let's eat there.", "ko": "알겠어요. 거기에서 식사해요."}, {"sp": "M", "en": "Great. Just let me grab my jacket before we head out.", "ko": "좋습니다. 다만 우리가 출발하기 전에 제 재킷을 가져올게요."}], "gimg": "hk_t2_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "British-Am", "audio": "Test02_65-67.mp3", "qs": [{"n": 65, "q": "What does the woman say about the broccoli soup?", "opts": ["It is not very popular.", "It is provided free of charge.", "It is served with a salad.", "It is no longer available."], "ans": 3, "ko": "여자는 브로콜리 수프에 관해 무엇을 말하는가?"}, {"n": 66, "q": "According to the man, what happened last month?", "opts": ["A produce supplier went out of business.", "A restaurant hosted a company event.", "A seasonal dish was added to the menu.", "A lawyer announced his retirement."], "ans": 1, "ko": "남자에 따르면, 지난달에 무슨 일이 일어났는가?"}, {"n": 67, "q": "Look at the graphic. How much will the man pay?", "opts": ["$12.99", "$11.99", "$10.99", "$13.99"], "ans": 3, "ko": "시각 자료를 보시오. 남자는 얼마를 지불할 것인가?"}], "script": [{"sp": "W", "en": "Good evening, sir. Are you ready to order?", "ko": "안녕하세요, 손님. 주문하시겠어요?"}, {"sp": "M", "en": "Yes. Do you still have the broccoli soup? I don't see it listed.", "ko": "네. 아직 브로콜리 수프가 있나요? 목록에 포함된 것 같지 않아서요."}, {"sp": "W", "en": "I'm sorry, but that dish is only available in the winter.", "ko": "죄송하지만, 그 요리는 겨울에만 주문 가능합니다."}, {"sp": "M", "en": "That's too bad. I ordered it last month when my law firm held its anniversary dinner here, and I quite enjoyed it. I'll get one of your specials, then—the steak pizza, please.", "ko": "정말 안타깝네요. 지난달에 저희 법률 회사가 이곳에서 기념일 만찬을 열었을 때 그것을 주문했었고 정말 잘 먹었거든요. 그럼, 특선 요리 중 하나인 스테이크 피자로 할게요."}, {"sp": "W", "en": "I apologize again, sir. Our kitchen is out of beef for that dish. We can offer you a variation with bacon at the same price, though, if you'd prefer.", "ko": "다시 한번 사과드립니다, 손님. 저희 주방에 그 요리를 위한 소고기가 다 떨어졌습니다. 하지만, 원하신다면 같은 가격에 베이컨이 들어간 변형된 요리를 제공해드릴 수 있습니다."}, {"sp": "M", "en": "No problem. I'll have that, then.", "ko": "문제없어요. 그럼 그걸로 할게요."}], "gimg": "hk_t2_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "Australian-American", "audio": "Test02_68-70.mp3", "qs": [{"n": 68, "q": "Why do the speakers need to reorganize a section of the store?", "opts": ["A shipment will be delivered.", "An inspection will be conducted.", "A display will be removed.", "A sale will be held."], "ans": 3, "ko": "화자들은 왜 상점의 한 구획을 재편성해야 하는가?"}, {"n": 69, "q": "Look at the graphic. Where does the man want to put the cameras?", "opts": ["On Shelf 2", "On Shelf 3", "On Shelf 4", "On Shelf 5"], "ans": 1, "ko": "시각 자료를 보시오. 남자는 카메라를 어디에 놓고 싶어 하는가?"}, {"n": 70, "q": "What does the man say he will give the woman?", "opts": ["Order forms", "Customer information", "Camera accessories", "Promotional materials"], "ans": 3, "ko": "남자는 여자에게 무엇을 줄 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "Camilla, we will be selling our digital cameras and accessories at a discount next week. So, I'd like to reorganize that section of the store.", "ko": "Camilla, 우리는 다음 주에 디지털 카메라와 부속품들을 할인해서 판매할 거예요. 그래서, 저는 상점의 그 구획을 재편성하고자 해요."}, {"sp": "W", "en": "OK. What would you like me to do?", "ko": "알겠습니다. 제가 뭘 하면 될까요?"}, {"sp": "M", "en": "Please make sure that the cameras are prominently displayed. Um, why don't you move them to the shelf that currently holds the tripods?", "ko": "반드시 카메라가 눈에 띄게 전시되도록 해주세요. 음, 그것들을 현재 삼각대가 있는 칸으로 옮기는 게 어때요?"}, {"sp": "W", "en": "Sure. It would be better to have the tripods on the bottom shelf anyway as they are much larger than the flashes and lenses.", "ko": "그럼요. 어차피 삼각대가 플래시와 렌즈보다 훨씬 더 크니까 맨 아래 칸에 있는 게 나을 것 같아요."}, {"sp": "M", "en": "Right. Uh, one more thing... We should also hand out some fliers to customers to publicize this event. I'll give you them to distribute once the shelves have been rearranged.", "ko": "맞아요. 어, 한 가지 더요… 우리는 또한 고객들에게 이 행사를 홍보하기 위해 전단지들을 나누어 줘야 해요. 선반이 재배치되고 나면 당신이 그것들을 배부하시도록 드릴게요."}], "gimg": "hk_t2_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "American", "audio": "Test02_71-73.mp3", "qs": [{"n": 71, "q": "What are listeners asked to do?", "opts": ["Pick up their boarding passes", "Arrange bags in a specific way", "Tell attendants about meal preferences", "Go to another gate"], "ans": 1, "ko": "청자들은 무엇을 하도록 요청받는가?"}, {"n": 72, "q": "According to the speaker, what will volunteers receive?", "opts": ["Loyalty program points", "Free Internet access", "A coupon for food", "A seat upgrade"], "ans": 2, "ko": "화자에 따르면, 지원자들은 무엇을 받을 것인가?"}, {"n": 73, "q": "What does the speaker mention about passengers from economy class?", "opts": ["They can get onto an aircraft.", "They have to check in their baggage.", "They must confirm their seat before boarding.", "They will have to pay for special amenities."], "ans": 0, "ko": "화자는 일반석 승객들에 관해 무엇을 언급하는가?"}], "script": [{"sp": "M", "en": "This announcement is for all passengers of Jet Winds Flight 391 from Brisbane, Australia to Busan, South Korea. Today's flight is fully booked. Therefore, all overhead compartments are expected to be filled. Please remember that suitcases should be placed in the bins with their top handles facing the aisle so as to allow for more items to fit. Also, if anyone is willing to check their bag prior to boarding, please see airline agents at the ticketing desk. All such volunteers will receive a voucher for one free in-flight snack or beverage. Passengers from economy class may now begin boarding. Thank you for listening.", "ko": "호주 브리즈번에서 한국 부산으로 가는 Jet Winds 391편 승객 여러분들께 안내 말씀 드립니다. 오늘 항공편은 예약이 다 찼습니다. 따라서, 머리 위의 모든 짐칸이 다 찰 것으로 예상됩니다. 더 많은 물건들이 들어갈 수 있도록, 여행 가방은 맨 위의 손잡이가 통로 쪽을 향한 채로 짐칸에 보관되어야 한다는 것을 기억해 주십시오. 또한, 만약 탑승 이전에 가방을 부칠 의향이 있으신 분은 발권 데스크에서 항공사 승무원을 찾아주시기 바랍니다. 이렇게 해주시는 모든 지원자 분들께서는 무료 기내 간식 또는 음료 쿠폰을 받으실 것입니다. 일반석 승객 분들께서는 지금 탑승을 시작하실 수 있습니다. 들어주셔서 감사합니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "Australian", "audio": "Test02_74-76.mp3", "qs": [{"n": 74, "q": "According to the speaker, what is Mr. Rothman famous for?", "opts": ["Producing a fitness video", "Giving advice to celebrities", "Developing a health plan", "Writing a book about diets"], "ans": 2, "ko": "화자에 따르면, Mr. Rothman은 무엇으로 유명한가?"}, {"n": 75, "q": "What will Mr. Rothman probably discuss?", "opts": ["A way to get more vitamins", "A method for eliminating fat", "Some workout tips", "Some exercise benefits"], "ans": 1, "ko": "Mr. Rothman은 무엇을 논의할 것 같은가?"}, {"n": 76, "q": "What will listeners probably hear next?", "opts": ["A song", "A speech", "A traffic report", "An advertisement"], "ans": 1, "ko": "청자들은 다음에 무엇을 들을 것 같은가?"}], "script": [{"sp": "M", "en": "Good afternoon, and welcome to Getting Fit on WQZP. Today I will be interviewing Mitchell Rothman. He is a nutritionist who is well-known for creating a popular one-month weight loss program, which focuses on eliminating junk food and introducing apple cider vinegar. Did you know that this type of vinegar can play a key role in helping to burn extra fat in our bodies? Mr. Rothman will explain how this works in a few minutes. But first, I'd like to play an audio recording of his opening address at the Pacific Health Conference. The ideas he presents are quite fascinating.", "ko": "안녕하세요, WQZP의 Getting Fit입니다. 오늘 저는 Mitchell Rothman을 인터뷰할 것입니다. 그는 인스턴트 음식을 없애고 사과 식초를 접하는 것에 중점을 두는, 인기 있는 한 달짜리 체중 감량 프로그램을 만든 것으로 잘 알려진 영양학자입니다. 여러분은 이 종류의 식초가 우리 몸에 있는 여분의 지방을 태우는 데 핵심적인 역할을 한다는 것을 알고 계셨나요? 몇 분 후에 Mr. Rothman이 어떻게 이것이 작용하는지 설명할 것입니다. 하지만 우선, 태평양 보건 회의에서 한 그의 개회사 음성 녹음을 들려드리고 싶습니다. 그가 제시하는 방안들은 아주 흥미롭습니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test02_77-79.mp3", "qs": [{"n": 77, "q": "Who most likely is the speaker?", "opts": ["A talent agent", "A financial advisor", "A film director", "A book editor"], "ans": 3, "ko": "화자는 누구인 것 같은가? (A) 연예인 에이전트 (B) 재정 자문가 (C) 영화 감독 (D) 도서 편집자"}, {"n": 78, "q": "What does the speaker imply when she says, \"It was very well received\"?", "opts": ["A presentation went smoothly.", "A story was accepted for publication.", "An organization approved a grant request.", "An author altered a schedule."], "ans": 1, "ko": "화자는 \"그것은 매우 좋은 평가를 받았습니다\"라고 말할 때 무엇을 의도하는가? (A) 발표가 순조롭게 진행되었다. (B) 이야기는 출판을 승낙 받았다. (C) 단체가 보조금 요청을 승인했다. (D) 작가가 일정을 바꿨다."}, {"n": 79, "q": "What does the speaker ask the listener to do?", "opts": ["Visit an office", "Submit a document", "Respond to an e-mail", "Postpone a meeting"], "ans": 0, "ko": "화자는 청자에게 무엇을 하라고 요청하는가? (A) 사무실을 방문한다. (B) 서류를 제출한다. (C) 이메일에 답장을 보낸다. (D) 회의를 연기한다."}], "script": [{"sp": "W", "en": "Hi, this is Melissa Walton from BRX Publishing for Liam Roberts.", "ko": "안녕하세요, 저는 Liam Roberts와 통화하려고 하는 BRX 출판사의 Melissa Walton입니다."}, {"sp": "W", "en": "I'm calling because I reviewed the children's storybook you submitted with the other members of the editing committee.", "ko": "저는 귀하께서 제출하신 어린이 이야기책을 편집 위원회의 다른 위원들과 검토하여 전화 드립니다."}, {"sp": "W", "en": "It was very well received!", "ko": "그것은 매우 좋은 평가를 받았습니다!"}, {"sp": "W", "en": "We hope to have a final manuscript prepared by the end of the month.", "ko": "저희는 이번 달 말까지 최종 원고가 준비되기를 바랍니다."}, {"sp": "W", "en": "Since we may need to make a few minor changes, I'd like you to come into our office next week to discuss details about the characters and plot with our team.", "ko": "약간의 사소한 수정을 해야 할 필요가 있을 수 있으므로, 등장인물 및 구성에 대한 세부 사항을 저희 팀과 논의하기 위해 다음 주에 저희 사무실로 와주시면 좋겠습니다."}, {"sp": "W", "en": "Tuesday at 9 A.M. would be ideal, but we are flexible.", "ko": "화요일 오전 9시가 이상적이지만, 저희는 유동적입니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "1-Cn", "audio": "Test02_80-82.mp3", "qs": [{"n": 80, "q": "Where do the listeners work?", "opts": ["At a manufacturing facility", "At a retail outlet", "At an advertising agency", "At a television studio"], "ans": 2, "ko": "청자들은 어디에서 일하는가? (A) 제조 시설에서 (B) 소매점에서 (C) 광고 회사에서 (D) 텔레비전 스튜디오에서"}, {"n": 81, "q": "What did the speaker receive yesterday?", "opts": ["Some billing statements", "Some complimentary samples", "Some questionnaire results", "Some promotional flyers"], "ans": 2, "ko": "화자는 어제 무엇을 받았는가? (A) 청구서 (B) 무료 견본품 (C) 설문지 결과 (D) 홍보 전단지"}, {"n": 82, "q": "What does the speaker suggest?", "opts": ["Handing out products", "Brainstorming ideas", "Assembling a focus group", "Screening a second commercial"], "ans": 1, "ko": "화자는 무엇을 제안하는가? (A) 제품을 나누어주기 (B) 의견을 브레인스토밍하기 (C) 포커스 그룹을 모으기 (D) 두 번째 광고를 방영하기"}], "script": [{"sp": "M", "en": "Now that the advertisement we created for Appliance Outlet has been appearing on television for a couple of months, it's time to discuss its effectiveness.", "ko": "우리가 Appliance Outlet을 위해 만든 광고가 몇 달 동안 텔레비전에 방송되고 있으니, 그것의 효과에 대해 논의할 때입니다."}, {"sp": "M", "en": "The responses from a recent survey we conducted were passed along to me yesterday.", "ko": "우리가 실시한 최근 설문조사의 응답들이 어제 제게 전달되었습니다."}, {"sp": "M", "en": "I'm concerned about the responses to one of the questions.", "ko": "저는 질문들 중 하나에 대한 답변이 우려스럽습니다."}, {"sp": "M", "en": "Though most viewers enjoyed watching the advertisement, very few realized what was being promoted.", "ko": "대부분의 시청자들이 광고를 즐겁게 보긴 했지만, 무엇이 홍보되고 있는지 알아차린 사람은 거의 없었습니다."}, {"sp": "M", "en": "Obviously, this isn't the response we received from our original focus group.", "ko": "분명히, 이것은 우리가 원래의 포커스 그룹으로부터 받은 반응이 아닙니다."}, {"sp": "M", "en": "I think we should spend the next hour analyzing the customer responses and coming up with ways to avoid this problem with future advertisements.", "ko": "저는 우리가 고객들의 응답을 분석하고 앞으로의 광고들에 대해 이러한 문제를 방지할 방법을 찾는 데 이후의 시간을 보내야 한다고 생각합니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test02_83-85.mp3", "qs": [{"n": 83, "q": "Who most likely is the speaker?", "opts": ["A realtor", "A painter", "A customer service representative", "A product designer"], "ans": 1, "ko": "화자는 누구인 것 같은가? (A) 부동산 중개인 (B) 페인트공 (C) 고객 서비스 직원 (D) 제품 디자이너"}, {"n": 84, "q": "What does the speaker mean when she says, \"I plan to head out after I get off the phone\"?", "opts": ["A customer wants to view samples.", "Additional measurements must be taken.", "Another product will be purchased.", "A project was completed early."], "ans": 2, "ko": "화자는 \"제가 전화를 끊은 후에 출발할 계획입니다\"라고 말할 때 무엇을 의도하는가? (A) 고객이 샘플을 보길 원한다. (B) 추가적인 치수가 측정되어야 한다. (C) 다른 제품이 구입될 것이다. (D) 프로젝트가 일찍 완료되었다."}, {"n": 85, "q": "What will the speaker probably do tomorrow?", "opts": ["Come back to a job site", "Contact her supervisor", "Visit a nearby store", "Hire a painting crew"], "ans": 0, "ko": "화자는 내일 무엇을 할 것 같은가? (A) 작업 장소로 다시 돌아온다. (B) 그녀의 상사에게 연락한다. (C) 근처의 가게를 방문한다. (D) 페인트 칠 할 직원들을 고용한다."}], "script": [{"sp": "W", "en": "Mr. Kunchai, this is Polly Jenkins calling.", "ko": "Mr. Kunchai, 저는 Polly Jenkins입니다."}, {"sp": "W", "en": "I'm sorry to bother you, but I've run into a small problem.", "ko": "신경 쓰이게 해드려 죄송하지만, 작은 문제에 부딪혔습니다."}, {"sp": "W", "en": "It turns out that the paint I bought to use in your living room is the wrong color.", "ko": "귀하의 거실을 칠하는 데 사용하기 위해 구매한 페인트가 잘못된 색깔인 것으로 드러났습니다."}, {"sp": "W", "en": "Although the can says that it contains tan paint, the paint is actually a light green color.", "ko": "용기에는 황갈색 페인트가 들어 있다고 쓰여 있지만, 그 페인트는 사실 밝은 초록색입니다."}, {"sp": "W", "en": "Anyway, I plan to head out after I get off the phone.", "ko": "어쨌든, 제가 전화를 끊은 후에 출발할 계획입니다."}, {"sp": "W", "en": "I expect to lose at least an hour of work today by going to the store, which means I'll most likely need to return tomorrow to complete the project.", "ko": "가게에 감으로써 오늘 근무 시간 중 최소한 한 시간을 허비하게 될 것으로 예상하는데, 이는 프로젝트를 완료하기 위해 제가 아마 내일 다시 돌아올 필요가 있을 것 같다는 것을 의미합니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "1-Au", "audio": "Test02_86-88.mp3", "qs": [{"n": 86, "q": "According to the speaker, what will take place during the weekend?", "opts": ["A client meeting", "Some special tutorials", "Some office renovations", "An equipment upgrade"], "ans": 3, "ko": "화자에 따르면, 주말 동안 무슨 일이 일어날 것인가? (A) 고객과의 회의 (B) 특별 개인 지도 (C) 사무실 개조 작업 (D) 장비 업그레이드"}, {"n": 87, "q": "What does the speaker ask listeners to do?", "opts": ["Save some data", "Print out some documents", "Download a program", "Replace some desks"], "ans": 0, "ko": "화자는 청자들에게 무엇을 하라고 요청하는가? (A) 자료를 저장한다. (B) 문서를 인쇄한다. (C) 프로그램을 다운로드한다. (D) 책상들을 교체한다."}, {"n": 88, "q": "Who is Caroline Schmidt?", "opts": ["A television broadcaster", "A security guard", "A department supervisor", "A sales representative"], "ans": 2, "ko": "Caroline Schmidt는 누구인가? (A) 텔레비전 방송인 (B) 경비원 (C) 부서 관리자 (D) 판매원"}], "script": [{"sp": "M", "en": "One last thing before we return to work.", "ko": "업무에 복귀하기 전 마지막으로 한 가지가 더 있습니다."}, {"sp": "M", "en": "We'll be replacing all of our computers with new models this upcoming weekend.", "ko": "다가오는 주말에, 우리의 모든 컴퓨터를 새로운 모델로 교체할 것입니다."}, {"sp": "M", "en": "Tomorrow, I'll distribute portable flash drives.", "ko": "내일, 제가 휴대용 플래시 드라이브를 나누어 드릴 것입니다."}, {"sp": "M", "en": "Please back up all of your files, and then save them to the company's secure online cloud network.", "ko": "여러분의 모든 파일들을 백업하시고, 그것들을 회사의 온라인 보안 네트워크에 저장하시기 바랍니다."}, {"sp": "M", "en": "Our IT manager, Caroline Schmidt, will be deleting all data from the old devices on Friday before they're recycled.", "ko": "우리의 IT 부장인 Caroline Schmidt는 이전 기기들이 재활용되기 전에 거기에 있는 모든 자료를 금요일에 삭제할 것입니다."}, {"sp": "M", "en": "Financial corporations like ours must be sure to do this to protect our clients' confidential information.", "ko": "우리와 같은 금융 회사들은 고객들의 기밀 정보를 보호하기 위해 반드시 이것을 해야 합니다."}, {"sp": "M", "en": "If you have any questions or concerns, please see me after the meeting.", "ko": "어떤 질문이나 우려가 있다면, 회의 이후에 저를 찾아와 주시기 바랍니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test02_89-91.mp3", "qs": [{"n": 89, "q": "What is the speaker planning?", "opts": ["An awards banquet", "A shareholder meeting", "A retirement gathering", "An employee orientation"], "ans": 2, "ko": "화자가 계획하고 있는 것은 무엇인가? (A) 시상식 연회 (B) 주주 총회 (C) 은퇴식 (D) 직원 오리엔테이션"}, {"n": 90, "q": "What does the speaker imply when she says, \"I just found out Mr. Evanston is a vegetarian\"?", "opts": ["She and Mr. Evanston like similar foods.", "She thinks a cuisine will work well.", "Some caterers cannot fulfill a guest's request.", "Some changes to an order need to be made."], "ans": 3, "ko": "화자는 \"저는 Mr. Evanston이 채식주의자라는 것을 이제서야 알게 되었어요\"라고 말할 때 무엇을 의도하는가? (A) 그녀와 Mr. Evanston은 비슷한 음식을 좋아한다. (B) 그녀는 요리법이 성공적일 것이라고 생각한다. (C) 음식 공급 업체가 손님의 요구 사항을 만족시킬 수 없다. (D) 주문에 대해 몇 가지 수정이 이루어져야 한다."}, {"n": 91, "q": "What does the speaker ask the listener to do?", "opts": ["Revise an invitation", "Research other venue options", "Bring some special dishes", "Contact guests"], "ans": 3, "ko": "화자는 청자에게 무엇을 해달라고 요청하는가? (A) 초대장을 수정한다. (B) 다른 장소 선택권을 찾아본다. (C) 특별한 요리들을 가져온다. (D) 손님들에게 연락한다."}], "script": [{"sp": "W", "en": "Richard, it's Sandra.", "ko": "Richard, 저 Sandra예요."}, {"sp": "W", "en": "Thanks again for offering to help me prepare for Mr. Evanston's retirement party.", "ko": "제가 Mr. Evanston의 은퇴 파티를 준비하는 것을 도와주시기로 한 것에 대해 다시 한 번 감사드려요."}, {"sp": "W", "en": "I already reserved the banquet room and put in the catering order.", "ko": "저는 이미 연회장을 예약했고 출장 요리를 주문했어요."}, {"sp": "W", "en": "However, I just found out Mr. Evanston is a vegetarian.", "ko": "그러나, 저는 Mr. Evanston이 채식주의자라는 것을 이제서야 알게 되었어요."}, {"sp": "W", "en": "Could you let me know if any of our other guests have restrictions before I contact the caterer?", "ko": "제가 음식 공급업자에게 연락하기 전에 제한 사항이 있는 다른 손님들이 있는지 알려주시겠어요?"}, {"sp": "W", "en": "Please send an e-mail to everyone who intends to join and inquire about their preferences.", "ko": "파티에 참가하려는 모든 사람들에게 이메일을 보내 그들의 선호 사항에 대해 알아봐주세요."}, {"sp": "W", "en": "Then, forward me the results.", "ko": "그다음에, 그 결과들을 저에게 전달해 주세요."}, {"sp": "W", "en": "It'd be great if you could have that done before the end of the day.", "ko": "그것을 오늘 내에 해주시면 좋을 것 같아요."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "1-Br", "audio": "Test02_92-94.mp3", "qs": [{"n": 92, "q": "What will take place on Wednesday?", "opts": ["A career fair", "An educational talk", "A book signing", "A charity fund-raiser"], "ans": 1, "ko": "수요일에 무엇이 열릴 것인가? (A) 취업 박람회 (B) 교육 강연 (C) 책 사인회 (D) 자선 기금 모금 행사"}, {"n": 93, "q": "Why will an event be held at the Selby Auditorium?", "opts": ["It offers an affordable rate.", "It has an excellent sound system.", "It can accommodate a big audience.", "It is close to an association's headquarters."], "ans": 2, "ko": "행사는 왜 Selby 강당에서 열릴 것인가? (A) 저렴한 요금을 제공한다. (B) 훌륭한 음성 시스템을 가지고 있다. (C) 많은 청중들을 수용할 수 있다. (D) 협회의 본사와 가깝다."}, {"n": 94, "q": "How can an event be attended for free?", "opts": ["By completing a survey", "By doing volunteer work", "By arriving at a venue early", "By verifying a membership"], "ans": 3, "ko": "어떻게 행사에 무료로 참석할 수 있는가? (A) 설문지를 작성함으로써 (B) 자원봉사를 함으로써 (C) 장소에 일찍 도착함으로써 (D) 회원임을 입증함으로써"}], "script": [{"sp": "M", "en": "In local news, the renowned Derby Botanical Society plans to invite expert gardener Lorenzo Granada to its biannual meeting at 7 P.M. on Wednesday.", "ko": "지역 뉴스로, 명성 있는 Derby 식물 협회가 전문 원예사인 Lorenzo Granada를 수요일 오후 7시에 연 2회 열리는 회의에 초청할 계획입니다."}, {"sp": "M", "en": "Ms. Granada, who will be traveling all the way from Barcelona, is scheduled to give a lecture on growing orchids.", "ko": "바르셀로나에서 먼 길을 오게 될 Ms. Granada는 난초를 재배하는 것에 관한 강의를 하기로 되어 있습니다."}, {"sp": "M", "en": "Usually, the association gathers at Lakeside Community Center for such events, but this time the meeting will take place at Selby Auditorium.", "ko": "보통, 협회는 이러한 행사를 위해 Lakeside 시민 문화 회관에서 모이지만, 이번에는 모임이 Selby 강당에서 열릴 것입니다."}, {"sp": "M", "en": "The change is due to the fact that a large turnout is anticipated.", "ko": "이 변동은 많은 수의 참가자들이 예상된다는 사실 때문입니다."}, {"sp": "M", "en": "You can pay $10 to enter or present a Derby Botanical Society member card for complimentary admission.", "ko": "입장하기 위해서는 10달러를 지불하시거나 무료 입장을 위해 Derby 식물 협회 회원 카드를 제시하시면 됩니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "W-Au", "audio": "Test02_95-97.mp3", "qs": [{"n": 95, "q": "What type of event is most likely taking place?", "opts": ["A training session", "A book launch", "A financial convention", "A job fair"], "ans": 2, "ko": "열리고 있는 행사의 종류를 묻는 문제이므로, 질문의 핵심어구(type of event ~ taking place)와 관련된 내용을 주의 깊게 듣는다. \"Our next speaker here at the Cape Town Finance Forum is Lisa Duval\"이라며 이곳 케이프타운 금융 포럼의 다음 연사는 Lisa Duval이라고 한 것을 통해 금융 컨벤션이 열리고 있음을 알 수 있다. 따라서 정답은 (C) A financial convention이다. 바꾸어 표현하기: Finance Forum 금융 포럼 → A financial convention 금융 컨벤션"}, {"n": 96, "q": "Look at the graphic. Which of Lisa Duval's books was released most recently?", "opts": ["Tomorrow's Export Market", "Where the Jobs Have Gone", "Evaluating Globalization", "The Biggest Tech Boom"], "ans": 1, "ko": "Lisa Duval의 도서들 중에서 가장 최근에 출간된 것을 묻는 문제이므로, 제시된 평가 사이트의 정보를 확인한 뒤 질문의 핵심어구(Lisa Duval's books ~ released most recently)와 관련된 내용을 주의 깊게 듣는다. \"her[Lisa Duval] most recent book, which was released a week ago, quickly topped sales charts and has been awarded four stars by PageFlipper.com.\"이라며 Lisa Duval의 최신 도서는 일주일 전에 출간되었는데, 판매 차트에서 재빨리 1위를 차지하였고 PageFlipper.com에서 별점 4개를 받았다고 하였으므로 별점이 4개인 일자리는 어디로 사라졌는가가 가장 최근에 출간된 도서임을 평가 사이트에서 알 수 있다. 따라서 정답은 (B) Where the Jobs Have Gone이다."}, {"n": 97, "q": "According to the speaker, what topic will be discussed?", "opts": ["Recycling programs", "Urban design", "Organically grown food", "Renewable energy"], "ans": 3, "ko": "논의될 주제를 묻는 문제이므로, 질문의 핵심어구(topic will be discussed)와 관련된 내용을 주의 깊게 듣는다. \"today she[Lisa Duval]'ll be discussing the current direction of the solar panel industry here in South Africa\"라며 오늘 Lisa Duval이 이곳 남아프리카의 태양 전지판 산업의 현재 동향에 대해 논의할 것이라고 한 말을 통해 태양 전지판 산업 즉, 재생 가능한 에너지에 대해 논의될 것임을 알 수 있다. 따라서 정답은 (D) Renewable energy이다. 바꾸어 표현하기: the solar panel industry 태양 전지판 산업 → Renewable energy 재생 가능한 에너지"}], "script": [{"sp": "W", "en": "Our next speaker here at the Cape Town Finance Forum is Lisa Duval, an economist who works for the Department of Budget and Planning. Dr. Duval has also written a number of best-selling books, including one about the growth of technology companies—the first one she ever published. In fact, her most recent book, which was released a week ago, quickly topped sales charts and has been awarded four stars by PageFlipper.com. Anyway, today she'll be discussing the current direction of the solar panel industry here in South Africa. Please welcome her with a big round of applause.", "ko": "이곳 케이프타운 금융 포럼의 다음 연사는 예산 기획처에서 근무하는 경제학자 Lisa Duval입니다. Dr. Duval은 또한 처음으로 출판한 도서인 기술 회사들의 성장에 관한 도서를 포함하여, 많은 베스트셀러 도서들을 집필했습니다. 사실, 그녀의 최신 도서는 일주일 전에 출간되었는데, 판매 차트에서 재빨리 1위를 차지하였고 PageFlipper.com에서 별점 4개를 받았습니다. 어쨌든, 오늘 그녀는 이곳 남아프리카의 태양 전지판 산업의 현재 동향에 대해 논의할 것입니다. 큰 박수로 그녀를 환영해 주기 바랍니다."}], "gimg": "hk_t2_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "M-Cn", "audio": "Test02_98-100.mp3", "qs": [{"n": 98, "q": "Look at the graphic. Who is the message for?", "opts": ["Carl Hendrickson", "Melody Ray", "Miyuki Watanabe", "Evan Silverton"], "ans": 1, "ko": "메시지를 받을 사람을 묻는 문제이므로, 제시된 일정표의 정보를 확인한 뒤 질문의 핵심어구(Who ~ message for)와 관련된 내용을 주의 깊게 듣는다. \"We met last Thursday at the AIDQUEST Conference. After your talk on how to use social media to promote organizations, we chatted a bit\"이라며 지난 목요일에 AIDQUEST 학회에서 만났다고 한 뒤, 단체를 홍보하기 위해 소셜미디어를 사용하는 방법에 관한 청자의 강연 후에 이야기를 약간 나누었다고 하였으므로, 메시지는 AIDQUEST 학회에서 소셜미디어 활용하기를 주제로 강연한 Melody Ray를 위한 것임을 일정표에서 알 수 있다. 따라서 정답은 (B) Melody Ray이다."}, {"n": 99, "q": "Why does the speaker want to meet with the listener?", "opts": ["To prepare a presentation", "To talk about a convention", "To discuss a job offer", "To congratulate a colleague"], "ans": 2, "ko": "화자가 청자를 만나고 싶어 하는 이유를 묻는 문제이므로, 질문의 핵심어구(meet with the listener)와 관련된 내용을 주의 깊게 듣는다. \"I'd like to hire you as a consultant. If you're interested, we should meet to discuss the position.\"이라며 청자를 자문 위원으로 고용하고 싶은데, 만약 청자가 관심이 있다면 이 자리에 대해 논의하기 위해 만나면 좋을 것 같다고 하였다. 따라서 정답은 (C) To discuss a job offer이다."}, {"n": 100, "q": "What does the speaker say he must do next Monday?", "opts": ["Attend a company picnic", "Respond to an advisor", "Meet with a potential client", "Stop by a college campus"], "ans": 3, "ko": "화자가 다음 주 월요일에 해야 한다고 말하는 것을 묻는 문제이므로, 질문의 핵심어구(next Monday)와 관련된 내용을 주의 깊게 듣는다. \"Next week would be ideal. Monday won't work for me because I've got to attend an event at a local university\"라며 다음 주가 이상적일 것 같은데 월요일은 지역 대학교에서 열리는 행사에 참석해야 하므로 가능하지 않다고 하였다. 따라서 정답은 (D) Stop by a college campus이다. 바꾸어 표현하기: attend an event at a local university 지역 대학교에서 열리는 행사에 참석하다 → Stop by a college campus 대학 캠퍼스에 들르다"}], "script": [{"sp": "M", "en": "I'm not sure if you remember me, but my name is Hector Fuentes. We met last Thursday at the AIDQUEST Conference. After your talk on how to use social media to promote organizations, we chatted a bit regarding my own foundation, Education Now. I was very impressed with what you had to say, and I'd like to hire you as a consultant. If you're interested, we should meet to discuss the position. Next week would be ideal. Monday won't work for me because I've got to attend an event at a local university, but I'll be free on Tuesday.", "ko": "저를 기억하시는지 모르겠지만, 제 이름은 Hector Fuentes입니다. 우리는 지난 목요일에 AIDQUEST 학회에서 만났습니다. 단체를 홍보하기 위해 소셜미디어를 사용하는 방법에 관한 당신의 강연 후에 우리는 저의 재단인 Education Now에 대해 이야기를 약간 나누었습니다. 저는 당신이 말한 것에 대해 매우 좋은 인상을 받았고, 당신을 자문 위원으로 고용하고 싶습니다. 만약 당신이 관심이 있으시다면, 이 자리에 대해 논의하기 위해 저희가 만나면 좋겠습니다. 다음 주가 이상적일 것 같습니다. 월요일은 제가 지역 대학교에서 열리는 행사에 참석해야 하므로 가능하지 않지만 화요일에는 한가할 것입니다."}], "gimg": "hk_t2_g98.jpg"}]};
